import{_ as a,o as t,c as i,a2 as o}from"./chunks/framework.Bix3-HpO.js";const d=JSON.parse('{"title":"Review Page Templates","description":"Review Page Templates for Akurai Theme","frontmatter":{"title":"Review Page Templates","description":"Review Page Templates for Akurai Theme","weight":50,"extra":{"order":50},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/review-page-templates"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/review-page-templates"}],["meta",{"property":"og:title","content":"Review Page Templates"}],["meta",{"property":"og:description","content":"Review Page Templates for Akurai Theme"}],["meta",{"name":"twitter:title","content":"Review Page Templates"}],["meta",{"name":"twitter:description","content":"Review Page Templates for Akurai Theme"}]]},"headers":[],"relativePath":"docs/akurai/review-page-templates.md","filePath":"docs/akurai/review-page-templates.md"}'),r={name:"docs/akurai/review-page-templates.md"};function s(n,e,l,p,h,m){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="review-page-templates" tabindex="-1">Review Page Templates <a class="header-anchor" href="#review-page-templates" aria-label="Permalink to &quot;Review Page Templates&quot;">​</a></h1><p>You can define different templates for review pages in Akurai.</p><hr><h2 id="using-review-page-templates" tabindex="-1">Using Review Page Templates <a class="header-anchor" href="#using-review-page-templates" aria-label="Permalink to &quot;Using Review Page Templates&quot;">​</a></h2><p>There are 3 page templates available for displaying <strong>Review Pages</strong> in your website.</p><ol><li>Default Template</li><li>Review with Sidebar</li><li>Banner Template</li></ol><h3 id="default-template" tabindex="-1">Default Template <a class="header-anchor" href="#default-template" aria-label="Permalink to &quot;Default Template&quot;">​</a></h3><p>The default template layout has 100% wide content area, no sidebars, no widgets. You can display a <a href="#review-page-hero">hero section</a> on top reviews with default template.</p><h3 id="review-with-sidebar" tabindex="-1">Review with Sidebar <a class="header-anchor" href="#review-with-sidebar" aria-label="Permalink to &quot;Review with Sidebar&quot;">​</a></h3><p>This is just like the default template, however it has a sidebar on the right, where you can add review page and general widgets. You can display a <a href="#review-page-hero">hero section</a> on top reviews with default template.</p><h3 id="banner-template" tabindex="-1">Banner Template <a class="header-anchor" href="#banner-template" aria-label="Permalink to &quot;Banner Template&quot;">​</a></h3><p>Review pages with the banner template have a nice section on top of the page to display important review information such as the logo, bonus, country support, payment methods, etc. You can change its background color for each review to make them unique.</p><h3 id="review-page-hero" tabindex="-1">Review Page Hero <a class="header-anchor" href="#review-page-hero" aria-label="Permalink to &quot;Review Page Hero&quot;">​</a></h3><p>Default review pages have a hero section at the top to display information about the sportsbook such as the logo, ratings, bonus, etc. You can customize the hero to display in 1 or 2 columns. Also you can choose to display the page heading (<code>h1</code> tag) below or above the hero. You can make this changes in <a href="/docs/akurai/customizations#review-options">Customizer → Review Options</a>.</p>',14)])])}const u=a(r,[["render",s]]);export{d as __pageData,u as default};
